import React, { useState, useEffect } from "react";

const TaskForm = ({ onTaskCreated, onTaskUpdated, editingTask, onCancelEdit, categories }) => {
  const [formData, setFormData] = useState({
    title: "",
    description: "",
    deadline: "",
    categoryId: "",
  });
  const [error, setError] = useState("");

  useEffect(() => {
    if (editingTask) {
      // Formatear la fecha para que encaje en el input datetime-local si viene del backend
      let formattedDeadline = "";
      if (editingTask.deadline) {
        // Cortamos los segundos o milisegundos si sobran para que datetime-local lo entienda (YYYY-MM-DDTHH:mm)
        formattedDeadline = editingTask.deadline.substring(0, 16);
      }

      setFormData({
        title: editingTask.title || "",
        description: editingTask.description || "",
        deadline: formattedDeadline,
        categoryId: editingTask.categoryId || "",
      });
      setError("");
    } else {
      setFormData({ title: "", description: "", deadline: "", categoryId: "" });
    }
  }, [editingTask]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    // Validaciones
    if (!formData.title.trim()) {
      setError("El título de la tarea no puede estar vacío.");
      return;
    }
    if (!formData.categoryId) {
      setError("Debes seleccionar una categoría.");
      return;
    }

    // Preparar los datos
    const submitData = { ...formData };

    if (submitData.deadline) {
      // El backend requiere el formato exacto YYYY-MM-DDTHH:mm:ss
      // Si el input datetime-local no pone segundos, los añadimos
      if (submitData.deadline.length === 16) {
        submitData.deadline = submitData.deadline + ":00";
      }
    } else {
      submitData.deadline = null;
    }

    try {
      if (editingTask) {
        await onTaskUpdated(editingTask.id, submitData);
      } else {
        await onTaskCreated(submitData);
        setFormData({ title: "", description: "", deadline: "", categoryId: "" });
      }
    } catch (err) {
      setError("Hubo un problema al guardar la tarea. Revisa los datos o tu conexión.");
    }
  };

  return (
    <form
      onSubmit={handleSubmit}
      style={{
        marginBottom: "20px",
        border: "1px solid #ccc",
        borderRadius: "8px",
        padding: "20px",
        backgroundColor: "#f9f9f9"
      }}
    >
      <h3 style={{ marginTop: 0 }}>{editingTask ? "Editar Tarea" : "Nueva Tarea"}</h3>

      {error && <div style={{ color: "#721c24", marginBottom: "15px", padding: "10px", backgroundColor: "#f8d7da", border: "1px solid #f5c6cb", borderRadius: "5px" }}>⚠️ {error}</div>}

      <div style={{ marginBottom: "10px" }}>
        <input
          type="text"
          placeholder="Título de la tarea *"
          value={formData.title}
          onChange={(e) => setFormData({ ...formData, title: e.target.value })}
          style={{ width: "100%", padding: "8px", boxSizing: "border-box" }}
        />
      </div>

      <div style={{ marginBottom: "10px" }}>
        <textarea
          placeholder="Descripción (opcional)"
          value={formData.description}
          onChange={(e) => setFormData({ ...formData, description: e.target.value })}
          style={{ width: "100%", padding: "8px", boxSizing: "border-box", minHeight: "60px", fontFamily: "inherit" }}
        />
      </div>

      <div style={{ marginBottom: "15px", display: "flex", gap: "10px", flexWrap: "wrap" }}>
        <div style={{ flex: 1, minWidth: "200px" }}>
          <label style={{ display: "block", fontSize: "12px", color: "#555", marginBottom: "4px" }}>Fecha Límite</label>
          <input
            type="datetime-local"
            value={formData.deadline}
            onChange={(e) => setFormData({ ...formData, deadline: e.target.value })}
            style={{ width: "100%", boxSizing: "border-box", padding: "8px" }}
          />
        </div>

        <div style={{ flex: 1, minWidth: "200px" }}>
          <label style={{ display: "block", fontSize: "12px", color: "#555", marginBottom: "4px" }}>Categoría *</label>
          <select
            value={formData.categoryId}
            onChange={(e) => setFormData({ ...formData, categoryId: e.target.value })}
            style={{ width: "100%", boxSizing: "border-box", padding: "8px" }}
          >
            <option value="">Selecciona Categoría</option>
            {categories.map((cat) => (
              <option key={cat.id} value={cat.id}>
                {cat.title}
              </option>
            ))}
          </select>
        </div>
      </div>

      <div style={{ display: "flex", gap: "10px" }}>
        <button type="submit" style={{ flex: 2, padding: "10px", backgroundColor: "#007bff", color: "white", border: "none", borderRadius: "4px", cursor: "pointer", fontWeight: "bold" }}>
          {editingTask ? "💾 Guardar Cambios" : "➕ Añadir Tarea"}
        </button>
        {editingTask && (
          <button type="button" onClick={onCancelEdit} style={{ flex: 1, padding: "10px", backgroundColor: "#6c757d", color: "white", border: "none", borderRadius: "4px", cursor: "pointer" }}>
            ❌ Cancelar
          </button>
        )}
      </div>
    </form>
  );
};

export default TaskForm;
